 p1 = (bt->frac & 0xffffffffull) * x;
 p2 = (bt->frac >> 32) * x + (p1 >> 32);
 bt->sec *= x;
 bt->sec += (p2 >> 32);
 bt->frac = (p2 << 32) | (p1 & 0xffffffffull);
}

