bintime_shift(struct bintime *__bt, int __exp)
{

 if (__exp > 0) {
  __bt->sec <<= __exp;
  __bt->sec |= __bt->frac >> (64 - __exp);
  __bt->frac <<= __exp;
 } else if (__exp < 0) {
  __bt->frac >>= -__exp;
  __bt->frac |= (uint64_t)__bt->sec << (64 + __exp);
  __bt->sec >>= -__exp;
 }
}
